import { ZuploContext, ZuploRequest } from "@zuplo/runtime";

export default async function (
  request: ZuploRequest,
  context: ZuploContext,
  options: never,
  policyName: string
) {
  const tenantId = request.headers.get("x-mock-tenant-id");
  if (tenantId) {
    request.user = {
      sub: "mock-user",
      data: { tenantId }
    };
  } else {
    request.user = {
      sub: "mock-user",
      data: {}
    };
  }
  return request;
}

