import { ZuploContext, ZuploRequest, ZuploRequestInit } from "@zuplo/runtime";

export default async function (
  request: ZuploRequest,
  context: ZuploContext,
  options: never,
  policyName: string
) {
  const tenantId = request.user?.data?.tenantId;

  if (!tenantId) {
    return new Response(JSON.stringify({ error: "Missing tenantId" }), {
      status: 400,
      headers: { "content-type": "application/json" },
    });
  }

  context.custom.downstreamUrl = `https://${tenantId}.api.example.com`;

  const headers = new Headers(request.headers);
  headers.set("x-tenant-id", tenantId);

  const requestInit: ZuploRequestInit = {
    headers,
    user: request.user,
  };

  return new ZuploRequest(request, requestInit);
}

import { ZuploContext, ZuploRequest } from "@zuplo/runtime";

export default async function (
  request: ZuploRequest,
  context: ZuploContext,
  options: never,
  handlerName: string
) {
  return {
    downstreamUrl: context.custom.downstreamUrl,
    tenantHeader: request.headers.get("x-tenant-id"),
  };
}

